def test_single_comparison():
    result = parse("status = 'Active'")
    assert result == Comparison("status", "=", "Active")


def test_and_of_two_comparisons():
    result = parse("status = 'Active' and price > 100")
    assert isinstance(result, And)
    assert result.left == Comparison("status", "=", "Active")
    assert result.right == Comparison("price", ">", 100)


def test_or_binds_looser_than_and():
    result = parse("a = 1 or b = 2 and c = 3")
    assert isinstance(result, Or)
    assert result.left == Comparison("a", "=", 1)
    assert isinstance(result.right, And)
    assert result.right.left == Comparison("b", "=", 2)
    assert result.right.right == Comparison("c", "=", 3)


def test_not_binds_tighter_than_and():
    result = parse("not a = 1 and b = 2")
    assert isinstance(result, And)
    assert result.left == Not(Comparison("a", "=", 1))
